Page({
  data: {
    statusBarHeight: 44,
    recordId: null,
    duration: 3,
    completed: true,
    rating: 0,
    ratingText: '',
    notes: '',
    feedbackTags: [
      { name: '身心放松', selected: false },
      { name: '专注平静', selected: false },
      { name: '杂念较多', selected: false },
      { name: '时间太短', selected: false },
      { name: '效果很好', selected: false },
      { name: '需要坚持', selected: false }
    ]
  },

  ratingTexts: ['', '需要调整', '一般', '还不错', '很好', '非常好'],

  onLoad(options) {
    const systemInfo = wx.getSystemInfoSync()

    this.setData({
      statusBarHeight: systemInfo.statusBarHeight,
      recordId: options.recordId,
      duration: parseInt(options.duration) || 3,
      completed: options.completed === 'true'
    })
  },

  // 设置评分
  setRating(e) {
    const rating = parseInt(e.currentTarget.dataset.rating)
    this.setData({
      rating,
      ratingText: this.ratingTexts[rating]
    })

    wx.vibrateShort({ type: 'light' })
  },

  // 切换标签
  toggleTag(e) {
    const index = e.currentTarget.dataset.index
    const tags = this.data.feedbackTags
    tags[index].selected = !tags[index].selected

    this.setData({ feedbackTags: tags })
    wx.vibrateShort({ type: 'light' })
  },

  // 输入备注
  onNotesInput(e) {
    this.setData({
      notes: e.detail.value
    })
  },

  // 保存反馈
  saveFeedback() {
    const selectedTags = this.data.feedbackTags
      .filter(t => t.selected)
      .map(t => t.name)

    // 更新记录
    const records = wx.getStorageSync('zhiguan_records') || []
    const recordIndex = records.findIndex(r => r.id == this.data.recordId)

    if (recordIndex >= 0) {
      records[recordIndex].rating = this.data.rating
      records[recordIndex].tags = selectedTags
      records[recordIndex].notes = this.data.notes
      wx.setStorageSync('zhiguan_records', records)
    }

    wx.showToast({
      title: '保存成功',
      icon: 'success'
    })

    setTimeout(() => {
      wx.switchTab({
        url: '/pages/record/record'
      })
    }, 1000)
  },

  // 跳过
  skipFeedback() {
    wx.switchTab({
      url: '/pages/record/record'
    })
  }
})

/**pages/record/record.js**/
Page({
  data: {
    statusBarHeight: 44,
    totalSessions: 0,
    totalHours: 0,
    streak: 0,
    currentYear: 2026,
    currentMonth: 2,
    monthCount: 0,
    weekDays: ['日', '一', '二', '三', '四', '五', '六'],
    calendarDays: [],
    records: []
  },

  allRecords: [],

  onLoad() {
    const systemInfo = wx.getSystemInfoSync()
    const now = new Date()

    this.setData({
      statusBarHeight: systemInfo.statusBarHeight,
      currentYear: now.getFullYear(),
      currentMonth: now.getMonth() + 1
    })

    this.loadRecords()
  },

  onShow() {
    this.loadRecords()
  },

  // 加载记录
  loadRecords() {
    this.allRecords = wx.getStorageSync('zhiguan_records') || []

    // 计算统计数据
    this.calculateStats()

    // 生成日历
    this.generateCalendar()

    // 生成最近记录列表
    this.generateRecordList()
  },

  // 计算统计数据
  calculateStats() {
    const totalSessions = this.allRecords.length
    const totalMinutes = this.allRecords.reduce((sum, r) => sum + r.duration, 0)
    const totalHours = Math.floor(totalMinutes / 60 * 10) / 10
    const streak = this.calculateStreak()

    this.setData({ totalSessions, totalHours, streak })
  },

  // 计算连续天数
  calculateStreak() {
    if (this.allRecords.length === 0) return 0

    const dates = [...new Set(this.allRecords.map(r => new Date(r.date).toDateString()))]
      .sort((a, b) => new Date(b) - new Date(a))

    let streak = 0
    const today = new Date().toDateString()
    const yesterday = new Date(Date.now() - 86400000).toDateString()

    if (dates[0] === today || dates[0] === yesterday) {
      streak = 1
      for (let i = 1; i < dates.length; i++) {
        const prev = new Date(dates[i - 1])
        const curr = new Date(dates[i])
        if ((prev - curr) / 86400000 === 1) {
          streak++
        } else {
          break
        }
      }
    }

    return streak
  },

  // 生成日历
  generateCalendar() {
    const { currentYear, currentMonth } = this.data

    // 获取当月第一天是星期几
    const firstDay = new Date(currentYear, currentMonth - 1, 1).getDay()

    // 获取当月天数
    const daysInMonth = new Date(currentYear, currentMonth, 0).getDate()

    // 生成日历数据
    const calendarDays = []

    // 空白天数
    for (let i = 0; i < firstDay; i++) {
      calendarDays.push({ day: '', date: '', hasRecord: false })
    }

    // 当月天数
    const today = new Date()
    let monthCount = 0

    for (let day = 1; day <= daysInMonth; day++) {
      const dateStr = new Date(currentYear, currentMonth - 1, day).toDateString()
      const hasRecord = this.allRecords.some(r => 
        new Date(r.date).toDateString() === dateStr
      )

      if (hasRecord) monthCount++

      const isToday = today.getDate() === day && 
        today.getMonth() + 1 === currentMonth &&
        today.getFullYear() === currentYear

      calendarDays.push({
        day,
        date: dateStr,
        hasRecord,
        isToday
      })
    }

    this.setData({ calendarDays, monthCount })
  },

  // 生成记录列表
  generateRecordList() {
    const records = this.allRecords.slice(0, 20).map(r => {
      const date = new Date(r.date)
      return {
        ...r,
        day: date.getDate(),
        month: date.getMonth() + 1,
        stars: r.rating ? Array(r.rating).fill('★') : []
      }
    })

    this.setData({ records })
  },

  // 上一个月
  prevMonth() {
    let { currentYear, currentMonth } = this.data
    currentMonth--
    if (currentMonth < 1) {
      currentMonth = 12
      currentYear--
    }
    this.setData({ currentYear, currentMonth }, () => {
      this.generateCalendar()
    })
  },

  // 下一个月
  nextMonth() {
    let { currentYear, currentMonth } = this.data
    currentMonth++
    if (currentMonth > 12) {
      currentMonth = 1
      currentYear++
    }
    this.setData({ currentYear, currentMonth }, () => {
      this.generateCalendar()
    })
  }
})

